// API FAKE — Consulta de Presupuesto por patente
// 🔴 REEMPLAZAR con HTTP Request real:
// GET https://tu-api.com/presupuestos?patente={patente}&estado=vigente
// Headers: { Authorization: 'Bearer {TOKEN}' }
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const { phone, message } = $input.first().json;
const patente = message.toUpperCase().replace(/[^A-Z0-9]/g, '');

const esValida = /^[A-Z]{3}[0-9]{3}$/.test(patente) || /^[A-Z]{2}[0-9]{3}[A-Z]{2}$/.test(patente);
if (!esValida || patente.length < 6) {
  return [{
    json: {
      phone,
      response: [
        `⚠️ Patente *"${message}"* no reconocida.`,
        `Ingresala sin espacios: _AB123CD · ABC123_`
      ].join('\n')
    }
  }];
}

// FAKE API — Presupuesto simulado
const digits = patente.replace(/[^0-9]/g, '');
const suma = digits.split('').reduce((a, b) => a + parseInt(b), 0);

let presupuestoData;

if (suma <= 4) {
  presupuestoData = { encontrado: false, patente };
} else {
  const nro = 'PRES-' + String(suma * 100 + 2025);
  const hoy = new Date();
  const venc = new Date(hoy);
  venc.setDate(hoy.getDate() + (30 - suma % 10));

  const formatFecha = (d) => `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;

  const items = suma % 3 === 0
    ? [
        { descripcion: 'Mano de obra — cambio de embrague', monto: 120000 },
        { descripcion: 'Kit embrague (disco + plato + collarín)', monto: 185000 },
        { descripcion: 'Lubricantes y selladores', monto: 8500 }
      ]
    : [
        { descripcion: 'Mano de obra — service completo', monto: 45000 },
        { descripcion: 'Aceite 5W-40 sintético (4L)', monto: 32000 },
        { descripcion: 'Filtro de aceite', monto: 8000 },
        { descripcion: 'Filtro de aire', monto: 12500 }
      ];

  const subtotal = items.reduce((a, i) => a + i.monto, 0);
  const iva = Math.round(subtotal * 0.21);
  const total = subtotal + iva;

  presupuestoData = {
    encontrado: true,
    patente,
    nro,
    vehiculo: suma % 2 === 0 ? 'Toyota Hilux 2.8 TDI 2021' : 'Chevrolet Onix 1.0T 2022',
    fecha_emision: formatFecha(hoy),
    fecha_vencimiento: formatFecha(venc),
    vigente: venc >= hoy,
    mecanico: 'Roberto Díaz',
    items,
    subtotal,
    iva,
    total
  };
}

const session = staticData.sessions[phone] || {};
session.step = 'start';
session.data = {};
staticData.sessions[phone] = session;

return [{ json: { phone, presupuestoData } }];

