// 🔴 REEMPLAZAR con HTTP Request real:
// POST https://tu-api.com/reclamos
// Body: { patente, descripcion, phone, timestamp }
//
// Internamente debería:
// 1. Buscar último trabajo realizado para esa patente
// 2. Verificar si está dentro del período de garantía
// 3. Crear ticket de reclamo
// 4. Notificar al encargado de taller
// ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const { phone, message } = $input.first().json;
const descripcion = message.trim();

if (descripcion.length < 10) {
  return [{
    json: {
      phone,
      response: [
        `⚠️ La descripción es muy corta.`,
        `Por favor contanos el problema con más detalle para poder ayudarte mejor:`
      ].join('\n')
    }
  }];
}

const session = staticData.sessions[phone] || {};
const { patente } = session.data || {};

// FAKE API — Simular búsqueda de último trabajo y verificación de garantía
const digits = patente?.replace(/[^0-9]/g, '') || '0';
const suma = digits.split('').reduce((a, b) => a + parseInt(b), 0);

const hoy = new Date();
const fechaUltimoTrabajo = new Date(hoy);
fechaUltimoTrabajo.setDate(hoy.getDate() - (suma * 3));
const diasDesdeUltimoTrabajo = suma * 3;
const enGarantia = diasDesdeUltimoTrabajo <= 90;

const formatFecha = (d) => `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')}/${d.getFullYear()}`;

const nroReclamo = 'REC-' + String(Date.now()).slice(-6);
const apiResponse = {
  success: true,
  nroReclamo,
  patente,
  descripcion,
  ultimoTrabajo: {
    ordens: `OT-2025-${String(suma * 7).padStart(4, '0')}`,
    fecha: formatFecha(fechaUltimoTrabajo),
    descripcion: diasDesdeUltimoTrabajo <= 45 ? 'Service completo + cambio de pastillas' : 'Cambio de correa de distribución',
    diasTranscurridos: diasDesdeUltimoTrabajo
  },
  enGarantia,
  diasGarantia: 90,
  diasRestantesGarantia: Math.max(0, 90 - diasDesdeUltimoTrabajo),
  prioridad: enGarantia ? 'ALTA' : 'NORMAL',
  plazoContacto: enGarantia ? '24 horas hábiles' : '48 horas hábiles'
};

session.step = 'start';
session.data = {};
staticData.sessions[phone] = session;

return [{ json: { phone, reclamoData: apiResponse } }];
